  /*package*/ LibraryContributor createLibContributorForPlugins(PlatformPlugins pp) {
    return SetLibraryContributor.fromSet("Plugin contributor", getPluginLibDescriptors(pp));
  }

  public LibraryContributor createLibContributorForLibs(Iterable<String> libs, ClassLoader defaultCL) {
    Set<LibDescriptor> paths = new LinkedHashSet<LibDescriptor>();
    for (String lib : libs) {
      paths.add(new LibDescriptor(toIFile(new File(lib)), defaultCL));
    }
    return SetLibraryContributor.fromSet("Library contributor", paths);
  }

